import React, { useState, useEffect } from "react";
import { Container, Row } from "react-bootstrap";
import Button from "react-bootstrap/Button";
import Particle from "../Particle";
import { AiOutlineDownload } from "react-icons/ai";
import { Document, Page, pdfjs } from "react-pdf";
import "react-pdf/dist/esm/Page/AnnotationLayer.css";
import pdfFR from "../../Assets/../Assets/CV_FR_2025.pdf";
import pdfEN from "../../Assets/../Assets/CV_EN_2025.pdf";

pdfjs.GlobalWorkerOptions.workerSrc = `//cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjs.version}/pdf.worker.min.js`;

function ResumeNew() {
  const [width, setWidth] = useState(1200);
  const [language, setLanguage] = useState("EN"); // ✅ Mettre "EN" par défaut

  useEffect(() => {
    setWidth(window.innerWidth);
  }, []);

  const toggleLanguage = () => {
    setLanguage((prevLang) => (prevLang === "FR" ? "EN" : "FR"));
  };

  const selectedPdf = language === "EN" ? pdfEN : pdfFR;

  return (
    <div>
      <Container fluid className="resume-section">
        <Particle />
        
        {/* Bouton pour changer la langue */}
        <Row style={{ justifyContent: "center", position: "relative", marginBottom: "20px" }}>
          <Button variant="secondary" onClick={toggleLanguage} style={{ maxWidth: "250px" }}>
            {language === "FR" ? "Switch to English" : "Passer en Français"}
          </Button>
        </Row>

        {/* Bouton de téléchargement */}
        <Row style={{ justifyContent: "center", position: "relative" }}>
          <Button variant="primary" href={selectedPdf} target="_blank" style={{ maxWidth: "250px" }}>
            <AiOutlineDownload />
            &nbsp;Download CV ({language})
          </Button>
        </Row>

        {/* Affichage du CV */}
        <Row className="resume">
          <Document file={selectedPdf} className="d-flex justify-content-center">
            <Page pageNumber={1} scale={width > 700 ? 1.7 : 0.6} />
          </Document>
        </Row>

        {/* Bouton de téléchargement en bas */}
        <Row style={{ justifyContent: "center", position: "relative" }}>
          <Button variant="primary" href={selectedPdf} target="_blank" style={{ maxWidth: "250px" }}>
            <AiOutlineDownload />
            &nbsp;Download CV ({language})
          </Button>
        </Row>
      </Container>
    </div>
  );
}

export default ResumeNew;